1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
7	const LOYALTY_DISCOUNT_RATE = 0.2;
8	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
9	const FOLLOWUP_DISCOUNT_RATE = 0.15;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const INSURANCE_VALUES: Record<string, number> = {
21	  sword: 1000,
22	  amulet: 600,
23	  staff: 800,
24	  potion: 400,
25	  rune: 250,
26	  moonstone: 250,
27	};
28	
29	const DEDUCTIBLE = 100;
30	const CAP_MULTIPLIER = 2;
31	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
32	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
33	
34	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
35	type QuoteStep = { op: "quote"; items: Item[] };
36	type Damage = { itemType: string; amount: number };
37	type Incident = { cause: string; damages: Damage[] };
38	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
39	type Step = QuoteStep | ClaimStep;
40	type Customer = { yearsWithMHPCO: number };
41	type Scenario = { customer: Customer; steps: Step[] };
42	
43	const sum = (numbers: number[]): number =>
44	  numbers.reduce((total, n) => total + n, 0);
45	
46	const policyInsuranceSum = (items: Item[]): number =>
47	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
48	
49	const isHighEnchantmentForReimbursement = (item: Item): boolean =>
50	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD;
51	
52	const effectiveDamage = (item: Item, damageAmount: number): number =>
53	  isHighEnchantmentForReimbursement(item)
54	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
55	    : damageAmount;
56	
57	const findPolicyItem = (policyItems: Item[], itemType: string): Item =>
58	  policyItems.find((item) => item.type === itemType)!;
59	
60	const damagePayout = (policyItems: Item[], damage: Damage): number =>
61	  effectiveDamage(findPolicyItem(policyItems, damage.itemType), damage.amount) - DEDUCTIBLE;
62	
63	const claimResult = (policyItems: Item[], step: ClaimStep) => {
64	  const cap = CAP_MULTIPLIER * policyInsuranceSum(policyItems);
65	  const payout = sum(step.incident.damages.map((damage) => damagePayout(policyItems, damage)));
66	  return { payout, remainingCap: cap - payout };
67	};
68	
69	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
70	
71	const isBlockOfThreeAlike = (items: Item[]): boolean =>
72	  items.length === 3 && items.every((item) => item.type === items[0].type);
73	
74	const groupByType = (items: Item[]): Item[][] => {
75	  const groups: Record<string, Item[]> = {};
76	  for (const item of items) {
77	    (groups[item.type] ||= []).push(item);
78	  }
79	  return Object.values(groups);
80	};
81	
82	const groupBasePremium = (group: Item[]): number =>
83	  isBlockOfThreeAlike(group)
84	    ? BLOCK_OF_THREE_BASE_PREMIUM
85	    : sum(group.map(itemBasePremium));
86	
87	const itemsBasePremium = (items: Item[]): number =>
88	  sum(groupByType(items).map(groupBasePremium));
89	
90	const rateIfApplies = (amount: number, applies: boolean, rate: number): number =>
91	  applies ? amount * rate : 0;
92	
93	const cursedSurcharge = (item: Item): number =>
94	  rateIfApplies(itemBasePremium(item), item.cursed === true, CURSED_SURCHARGE_RATE);
95	
96	const highEnchantmentSurcharge = (item: Item): number =>
97	  rateIfApplies(
98	    itemBasePremium(item),
99	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
100	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
101	  );
102	
103	const itemSurchargesTotal = (items: Item[]): number =>
104	  sum(items.map((item) => cursedSurcharge(item) + highEnchantmentSurcharge(item)));
105	
106	const firstInsuranceSurcharge = (basePremium: number): number =>
107	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
108	
109	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
110	  rateIfApplies(
111	    basePremium,
112	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS,
113	    LOYALTY_DISCOUNT_RATE,
114	  );
115	
116	const followupDiscount = (basePremium: number, quoteIndex: number): number =>
117	  rateIfApplies(basePremium, quoteIndex >= 1, FOLLOWUP_DISCOUNT_RATE);
118	
119	const quotePremiumFor = (items: Item[], customer: Customer, quoteIndex: number): number => {
120	  const policyBase = itemsBasePremium(items);
121	  return Math.ceil(
122	    policyBase +
123	      itemSurchargesTotal(items) +
124	      firstInsuranceSurcharge(policyBase) -
125	      loyaltyDiscount(policyBase, customer) -
126	      followupDiscount(policyBase, quoteIndex) +
127	      PROCESSING_FEE,
128	  );
129	};
130	
131	export const runScenario = (input: Scenario): unknown => {
132	  const results: unknown[] = [];
133	  const quotedPolicies: Item[][] = [];
134	  for (const step of input.steps) {
135	    if (step.op === "quote") {
136	      const premium = quotePremiumFor(step.items, input.customer, quotedPolicies.length);
137	      results.push({ premium });
138	      quotedPolicies.push(step.items);
139	    } else {
140	      results.push(claimResult(quotedPolicies[step.policy], step));
141	    }
142	  }
143	  return { results };
144	};
