const claimResult = (policyItems: Item[], step: ClaimStep, remainingCapBefore: number) => {
  const computedPayout = sum(step.incident.damages.map((damage) => damagePayout(policyItems, damage)));
  const payout = Math.min(computedPayout, remainingCapBefore);
  return { payout, remainingCap: remainingCapBefore - payout };
};

