export const runScenario = (input: Scenario): unknown => {
  const results: unknown[] = [];
  const quotedPolicies: Item[][] = [];
  const remainingCaps: number[] = [];
  for (const step of input.steps) {
    if (step.op === "quote") {
      const premium = quotePremiumFor(step.items, input.customer, quotedPolicies.length);
      results.push({ premium });
      quotedPolicies.push(step.items);
      remainingCaps.push(CAP_MULTIPLIER * policyInsuranceSum(step.items));
    } else {
      const result = claimResult(quotedPolicies[step.policy], step, remainingCaps[step.policy]);
      remainingCaps[step.policy] = result.remainingCap;
      results.push(result);
    }
  }
  return { results };
};
